import{_ as o,o as t,c as a,aa as l}from"./chunks/framework.DHLMKRb3.js";const g=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog.md","filePath":"guide/changelog.md","lastUpdated":1775693750000}'),i={name:"guide/changelog.md"};function n(d,e,r,s,c,m){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="vunreleased" tabindex="-1">vUnreleased <a class="header-anchor" href="#vunreleased" aria-label="Permalink to &quot;vUnreleased&quot;">​</a></h2><p><strong>Common:</strong></p><ul><li>Added: New &#39;Debugging The World&#39; section to the official manual.</li><li>Fixed: /debug command now works properly for factions and settlements in diplomacy and strategic map (Rome 2 and Attila).</li></ul><hr><h2 id="v0-7-2" tabindex="-1">v0.7.2 <a class="header-anchor" href="#v0-7-2" aria-label="Permalink to &quot;v0.7.2&quot;">​</a></h2><p><strong>Common:</strong></p><ul><li>Added: Command <code>/consul_log_level &lt;integer&gt;</code> to set the consul log level persistently (e.g. 1=DEBUG, 2=INFO, 3=WARN).</li></ul><p><strong>Attila specific:</strong></p><ul><li>Fixed: /debug commands now properly prints information in Attila</li></ul><hr><h2 id="v0-7-1" tabindex="-1">v0.7.1 <a class="header-anchor" href="#v0-7-1" aria-label="Permalink to &quot;v0.7.1&quot;">​</a></h2><p><strong>Common:</strong></p><ul><li>Added: Commands for Lua profiling via <code>/profi_start</code>, <code>/profiler_start</code>, <code>/profi_stop &lt;filename&gt;</code>, and <code>/profiler_stop &lt;filename&gt;</code> commands.</li><li>Added: Command <code>/consul_debug_turn_time</code> to measure AI turn duration.</li><li>Added: New function <code>consul.debug.disable_all_diplomacy()</code> to instantly block all diplomacy actions between all factions.</li></ul><hr><h2 id="v0-7-0" tabindex="-1">v0.7.0 <a class="header-anchor" href="#v0-7-0" aria-label="Permalink to &quot;v0.7.0&quot;">​</a></h2><p><strong>Common:</strong></p><ul><li>Added: Official manual page with detailed instructions on how scripting works and how to create your own scripts: <a href="https://bukowa.github.io/ConsulScriptum" target="_blank" rel="noreferrer">https://bukowa.github.io/ConsulScriptum</a></li><li>Added: Direct link to the manual added to the top of the Steam Workshop description.</li><li>Added: Support for loading custom commands directly from the game directory or pack mods (you can now distribute your commands on the Steam Workshop).</li><li>Added: An example template with instructions is available in the mod pack as <code>consul/consul_commands.lua</code>.</li><li>Added: Command <code>/reload_custom_commands</code> to refresh installed custom commands without restarting the game.</li><li>Added: <code>consul.scriptum.entry</code> variable is now available in custom scripts, allowing them to identify and highlight the button (green) that triggered them. More info in the Consul documentation.</li><li>Fixed: Scriptum scripts now reload on any Consul component click to ensure they are fresh.</li><li>Added: Command <code>/logregistry</code> to dump all Lua registries and environments to <code>consul.log</code>.</li><li>Added: Command <code>/consul_debug_events</code> to toggle persistent event logging at startup.</li></ul><p><strong>Rome II specific:</strong></p><ul><li>Added: Specific Divide et Impera (DEI) commands for population management (<code>/dei_reset_all_pop</code>, <code>/dei_set_pop</code>, <code>/dei_reset_region_pop</code>).</li></ul><p><strong>Attila specific:</strong></p><ul><li>Added: Consul now works in Attila campaign battles (trigger via /use_in_battle)</li><li>Added: All game events for Attila for event tracking.</li></ul><hr><h2 id="v0-6-2" tabindex="-1">v0.6.2 <a class="header-anchor" href="#v0-6-2" aria-label="Permalink to &quot;v0.6.2&quot;">​</a></h2><p><strong>Common:</strong></p><ul><li>Fixed: The changelog module now correctly loads in campaign mode by fixing the require path.</li></ul><hr><h2 id="v0-6-1" tabindex="-1">v0.6.1 <a class="header-anchor" href="#v0-6-1" aria-label="Permalink to &quot;v0.6.1&quot;">​</a></h2><p><strong>Common:</strong></p><ul><li>Added: Changelog feature.</li><li>Added: Command /changelog - displays version notes.</li><li>Added: Command /changelog_read - marks current version as read and hides it on startup.</li></ul><hr><h2 id="v0-6-0" tabindex="-1">v0.6.0 <a class="header-anchor" href="#v0-6-0" aria-label="Permalink to &quot;v0.6.0&quot;">​</a></h2><p><strong>Common:</strong></p><ul><li>Added: Ported Consul to Attila: Total War (Alpha).</li><li>Added: GitHub release page is now available for the Attila build.</li></ul><p><strong>Rome II specific:</strong></p><ul><li>Fixed: Correctly hooked Rome2 systems.</li></ul><p><strong>Attila specific:</strong></p><ul><li>Fixed: Correctly hooked Attila systems.</li></ul><hr>',39)])])}const h=o(i,[["render",n]]);export{g as __pageData,h as default};
